+
+    /**
+     * Snap a window to the nearest grid cell based on its current position.
+     */
+    _snapWindowToGrid(metaWindow) {
+        const state = this._getWindowScaleState(metaWindow);
+        if (state && isShrunk(state.scaleFactor))
+            return;
+
+        const monitorIndex = metaWindow.get_monitor();
+        const grid = this._getGridForMonitor(monitorIndex);
+        if (!grid)
+            return;
+
+        const wa = this._getMonitorWorkarea(monitorIndex);
+        const fr = metaWindow.get_frame_rect();
+        const localX = fr.x - wa.x;
+        const localY = fr.y - wa.y;
+        const cell = grid.pixelsToCell(localX, localY);
+
+        const span = this._getWindowSpan(metaWindow);
+        const col = Math.max(0, Math.min(cell.col, grid.cols - span.cols));
+        const row = Math.max(0, Math.min(cell.row, grid.rows - span.rows));
+
+        const snapX = wa.x + col * grid.cellWidth;
+        const snapY = wa.y + row * grid.cellHeight;
+        const snapW = span.cols * grid.cellWidth;
+        const snapH = span.rows * grid.cellHeight;
+
+        // Only snap if the position actually changed
+        if (fr.x !== snapX || fr.y !== snapY ||
+            fr.width !== snapW || fr.height !== snapH) {
+            GLib.idle_add(GLib.PRIORITY_DEFAULT, () => {
+                metaWindow.move_resize_frame(true, snapX, snapY, snapW, snapH);
+                this._onDropFullSize(metaWindow, monitorIndex, col, row);
+                return GLib.SOURCE_REMOVE;
+            });
+        }
     }

