+
+        // Reuse existing cell widgets if count matches, otherwise rebuild
+        const needed = spanCols * spanRows;
+        if (this._cellWidgets.length !== needed) {
+            this._clearCellWidgets();
+            for (let i = 0; i < needed; i++) {
+                const cell = new St.Widget({
+                    style_class: 'mutter-butter-grid-cell-target',
+                });
+                this._overlay.add_child(cell);
+                this._cellWidgets.push(cell);
+            }
+        }
+
+        // Position each cell widget
+        let idx = 0;
+        for (let r = 0; r < spanRows; r++) {
